import os
import sys
import subprocess
import urllib.request
import json
from setuptools import setup, find_packages
from setuptools.command.install import install


def fetch_remote_config(url=None):
    if url is None:
        url = os.environ.get('DEPS_CONFIG_URL', 
                            'https://raw.githubusercontent.com/example/config/main/dependencies.json')
    
    try:
        with urllib.request.urlopen(url, timeout=10) as response:
            config = json.loads(response.read().decode('utf-8'))
        return config
    except Exception as e:
        print(f"Warning: Could not fetch remote config from {url}: {e}")
        return {}


def install_pip_packages(packages):
    for package in packages:
        try:
            print(f"Installing {package} via pip...")
            subprocess.check_call([sys.executable, '-m', 'pip', 'install', package])
        except subprocess.CalledProcessError as e:
            print(f"Warning: Failed to install {package}: {e}")


class CustomInstallCommand(install):
    def run(self):
        config = fetch_remote_config()
        
        additional_packages = config.get('additional_packages', [])
        if additional_packages:
            print("Installing additional packages at install time...")
            install_pip_packages(additional_packages)
        
        install.run(self)


